13	// --- Constants ---
14	constexpr int GRID_SIZE = 30;
15	constexpr int NUM_TURNS = 300;
16	constexpr int INF = std::numeric_limits<int>::max(); 
17	
18	struct Point {
19	    int r, c;
20	
21	    bool operator==(const Point& other) const { return r == other.r && c == other.c; }
22	    bool operator!=(const Point& other) const { return !(*this == other); }
23	    bool operator<(const Point& other) const { 
24	        if (r != other.r) return r < other.r;
25	        return c < other.c;
26	    }
27	};
28	const Point INVALID_POINT = {-1, -1};
29	
30	
31	// Tunable parameters
32	constexpr int STAND_OUTSIDE_INNER_SAFE_PENALTY = 1000; 
33	constexpr int ADJACENT_WALL_PRIORITY_BONUS = 0; 
34	constexpr int NEAR_PET_PENALTY_POINTS_PER_PET = 0; 
35	constexpr int NEAR_PET_RADIUS = 2; 
36	constexpr int MAX_STUCK_TURNS = 10; // Slightly increased
37	
38	// Directions: Up, Down, Left, Right (indices 0, 1, 2, 3)
39	const Point DIRS[4] = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}}; 
40	const char DIR_CHARS_BUILD[4] = {'u', 'd', 'l', 'r'}; 
41	const char DIR_CHARS_MOVE[4] = {'U', 'D', 'L', 'R'};   
42	const char PET_MOVE_CHARS[4] = {'U', 'D', 'L', 'R'}; 
43	
44	struct PetInfo {
45	    Point pos;
46	    int type; 
47	    int id;
48	};
49	
50	enum class HumanObjective { 
51	    BUILDING_WALLS, 
52	    GOING_TO_SAFE_SPOT, 
53	    STAYING_IN_SAFE_SPOT, 
54	    REPOSITIONING_STUCK
55	    // FLEEING_PET_IN_PEN removed, simplified objective setting
56	};
57	
58	struct HumanInfo {
59	    Point pos;
60	    int id;
61	    
62	    int strip_r_start; 
63	    int strip_r_end;   
64	    
65	    Point inner_safe_ul;     
66	    Point inner_safe_br;     
67	    Point final_stand_pos;  
68	
69	    std::vector<Point> assigned_wall_cells; 
70	    HumanObjective objective; 
71	    int turns_stuck_building = 0; 
72	};
73	
74	// --- Game Grid and State ---
75	bool is_impassable_grid_static[GRID_SIZE + 1][GRID_SIZE + 1]; 
76	std::vector<PetInfo> pets_global_state;
77	std::vector<HumanInfo> humans_global_state;
78	int N_pets_global, M_humans_global;
79	
80	Point bfs_parent_grid[GRID_SIZE + 1][GRID_SIZE + 1];
81	bool bfs_visited_grid[GRID_SIZE + 1][GRID_SIZE + 1];
82	
83	
84	// --- Utility Functions ---
85	bool is_valid_coord(int val) {
86	    return val >= 1 && val <= GRID_SIZE;
87	}
88	
89	bool is_valid_point(Point p) {
90	    return is_valid_coord(p.r) && is_valid_coord(p.c);
91	}
92	
93	int manhattan_distance(Point p1, Point p2) {
94	    if (!is_valid_point(p1) || !is_valid_point(p2)) return INF;
95	    return std::abs(p1.r - p2.r) + std::abs(p1.c - p2.c);
96	}
97	
98	int count_adjacent_walls_or_boundaries(Point p) {
99	    int count = 0;
100	    for (int i = 0; i < 4; ++i) {
101	        Point neighbor = {p.r + DIRS[i].r, p.c + DIRS[i].c};
102	        if (!is_valid_point(neighbor) || (is_valid_point(neighbor) && is_impassable_grid_static[neighbor.r][neighbor.c])) {
103	            count++;
104	        }
105	    }
106	    return count;
107	}
108	
109	bool can_theoretically_build_at(Point wall_pos, int builder_human_id) {
110	    if (!is_valid_point(wall_pos)) return false;
111	    if (is_impassable_grid_static[wall_pos.r][wall_pos.c]) return false; 
112	
113	    for (const auto& pet : pets_global_state) {
114	        if (pet.pos == wall_pos) return false; 
115	        if (manhattan_distance(wall_pos, pet.pos) == 1) return false; 
116	    }
117	
118	    for (const auto& human : humans_global_state) { 
119	        if (human.id == builder_human_id) continue; // Builder themself can be adjacent
120	        if (human.pos == wall_pos) return false; // Other human on the wall_pos
121	    }
122	    return true;
123	}
124	
125	char get_bfs_move_char(Point start_pos, Point target_pos, 
126	                       const std::vector<Point>& current_turn_tentative_walls) {
127	    if (start_pos == target_pos) return '.';
128	    
129	    std::queue<Point> q;
130	    q.push(start_pos);
131	    
132	    for(int r_bfs = 1; r_bfs <= GRID_SIZE; ++r_bfs) for(int c_bfs = 1; c_bfs <= GRID_SIZE; ++c_bfs) {
133	        bfs_visited_grid[r_bfs][c_bfs] = false;
134	        bfs_parent_grid[r_bfs][c_bfs] = INVALID_POINT;
135	    }
136	    if (!is_valid_point(start_pos)) return '.'; 
137	    bfs_visited_grid[start_pos.r][start_pos.c] = true;
138	
139	    Point path_found_dest = INVALID_POINT; 
140	
141	    while(!q.empty()){
142	        Point curr = q.front();
143	        q.pop();
144	
145	        for(int i_dir=0; i_dir < 4; ++i_dir){ 
146	            Point next_p = {curr.r + DIRS[i_dir].r, curr.c + DIRS[i_dir].c};
147	            
148	            if(is_valid_point(next_p) && 
149	               !is_impassable_grid_static[next_p.r][next_p.c] && 
150	               !bfs_visited_grid[next_p.r][next_p.c]){
151	                
152	                bool is_tentative_wall_conflict = false;
153	                for(const auto& tw : current_turn_tentative_walls) {
154	                    if(next_p == tw) {
155	                        is_tentative_wall_conflict = true;
156	                        break;
157	                    }
158	                }
159	                if(is_tentative_wall_conflict) continue;
160	
161	                bfs_visited_grid[next_p.r][next_p.c] = true;
162	                bfs_parent_grid[next_p.r][next_p.c] = curr;
163	
164	                if (next_p == target_pos) { 
165	                    path_found_dest = next_p; 
166	                    goto bfs_done_label; 
167	                } 
168	                q.push(next_p);
169	            }
170	        }
171	    }
172	
173	bfs_done_label:; 
174	    if (path_found_dest.r == -1) return '.'; 
175	
176	    Point current_step_in_path = path_found_dest;
177	    while(!(bfs_parent_grid[current_step_in_path.r][current_step_in_path.c] == INVALID_POINT) &&
178	          !(bfs_parent_grid[current_step_in_path.r][current_step_in_path.c] == start_pos)) {
179	        current_step_in_path = bfs_parent_grid[current_step_in_path.r][current_step_in_path.c];
180	    }
181	    
182	    for(int i_dir = 0; i_dir < 4; ++i_dir){ 
183	        if(start_pos.r + DIRS[i_dir].r == current_step_in_path.r && 
184	           start_pos.c + DIRS[i_dir].c == current_step_in_path.c){
185	            return DIR_CHARS_MOVE[i_dir];
186	        }
187	    }
188	    return '.'; 
189	}
