        double score_below = (double)area_below / 900.0 * std::pow(2.0, -(double)pets_below);

        // Choose the better side for this row
        bool top = (score_above >= score_below);
        double score = top ? score_above : score_below;
        int int_score = (int)(score * 100000);

        if (int_score > best_score) {
            best_score = int_score;
            best_row = r;
            best_top = top;
        }
    }

    wall_row = best_row;
    go_top = best_top;
}

