                if (target_col == -1) {
                    for (int c = 1; c <= GRID_SIZE; c++) {
                        if (!grid[wall_row][c] && !wall_built[c]) {
                            int dist = std::abs(humans[i].r - wall_row) + std::abs(humans[i].c - c);
                            if (dist < min_dist) {
                                min_dist = dist;
                                target_col = c;
                            }
                        }
                    }
                }

                if (target_col == -1) {
