                    // Best stand positions: (wall_row-1, target_col) or (wall_row+1, target_col)
                    // or (wall_row, target_col-1) or (wall_row, target_col+1)

                    // Prefer standing on the safe side
                    Point stand_pos;
                    if (go_top) {
                        stand_pos = {wall_row - 1, target_col};
                    } else {
                        stand_pos = {wall_row + 1, target_col};
