                        for (int r = wall_row + 1; r <= GRID_SIZE; r++) {
                            for (int c = 1; c <= GRID_SIZE; c++) {
                                if (passable(r, c)) {
                                    target = {r, c};
                                    goto found_target;
                                }
                            }
                        }
                    }
                    found_target:;
                }
                if (humans[i] == target) {
                    actions[i] = '.';
                } else {
