                }
            }
        }

        // Validate: no two humans moving to same cell, no move into wall being built
        std::vector<Point> move_targets(M, {-1, -1});
        std::vector<Point> walls_being_built;

        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
                        walls_being_built.push_back({humans[i].r + DR[d], humans[i].c + DC[d]});
