                    }
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        move_targets[i] = {humans[i].r + DR[d], humans[i].c + DC[d]};
                        break;
                    }
                }
            }
        }

