        for (int i = 0; i < M; i++) {
            if (move_targets[i].r == -1) continue;
            // Check against walls being built
            for (auto& w : walls_being_built) {
                if (move_targets[i] == w) { actions[i] = '.'; move_targets[i] = {-1, -1}; break; }
            }
            if (move_targets[i].r == -1) continue;
            // Check for valid move
            if (!passable(move_targets[i].r, move_targets[i].c)) {
                actions[i] = '.'; move_targets[i] = {-1, -1};
            }
        }

        // Output
        std::cout << actions << std::endl;

        // Apply actions to our state
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (valid(nr, nc)) {
                            grid[nr][nc] = true;
                            wall_built[nc] = true; // only correct if nr == wall_row
                        }
                        break;
                    }
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (passable(nr, nc)) {
                            humans[i] = {nr, nc};
                        }
                        break;
                    }
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N; i++) {
            std::string pet_move;
            std::cin >> pet_move;
            if (pet_move == ".") continue;
            for (char ch : pet_move) {
                for (int d = 0; d < 4; d++) {
