#include <cstring>

constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = std::numeric_limits<int>::max();

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const int DR[4] = {-1, 1, 0, 0};
const int DC[4] = {0, 0, -1, 1};
const char BUILD_CH[4] = {'u', 'd', 'l', 'r'};
const char MOVE_CH[4] = {'U', 'D', 'L', 'R'};

bool grid[GRID_SIZE + 2][GRID_SIZE + 2];

int N, M;
std::vector<Point> pets;
std::vector<int> pet_types;
std::vector<Point> humans;

bool valid(int r, int c) { return r >= 1 && r <= GRID_SIZE && c >= 1 && c <= GRID_SIZE; }
bool passable(int r, int c) { return valid(r, c) && !grid[r][c]; }

int bfs_dist[GRID_SIZE + 2][GRID_SIZE + 2];
Point bfs_parent[GRID_SIZE + 2][GRID_SIZE + 2];

void compute_bfs_from(Point src) {
    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Point> q;
    bfs_dist[src.r][src.c] = 0;
    q.push(src);
    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            int nr = cur.r + DR[d], nc = cur.c + DC[d];
            if (passable(nr, nc) && bfs_dist[nr][nc] == -1) {
                bfs_dist[nr][nc] = bfs_dist[cur.r][cur.c] + 1;
                bfs_parent[nr][nc] = cur;
                q.push({nr, nc});
            }
        }
    }
}

char move_toward(Point from, Point to) {
    if (from == to) return '.';
    compute_bfs_from(from);
    if (bfs_dist[to.r][to.c] == -1) return '.';

    // Trace back from 'to' to find the first step from 'from'
    Point cur = to;
    while (!(bfs_parent[cur.r][cur.c] == from)) {
        cur = bfs_parent[cur.r][cur.c];
    }
    for (int d = 0; d < 4; d++) {
        if (from.r + DR[d] == cur.r && from.c + DC[d] == cur.c) {
            return MOVE_CH[d];
        }
    }
    return '.';
}

bool can_build_wall(int r, int c) {
    if (!valid(r, c)) return false;
    if (grid[r][c]) return false;
    for (auto& p : pets) {
        if (p.r == r && p.c == c) return false;
        if (std::abs(p.r - r) + std::abs(p.c - c) == 1) return false;
    }
    for (int i = 0; i < M; i++) {
        if (humans[i].r == r && humans[i].c == c) return false;
    }
    return true;
}

int wall_row;
bool go_top;

void choose_wall_row() {
    int best_row = 15;
    double best_score = -1;
    bool best_top = true;

    for (int r = 3; r <= 28; r++) {
        int pets_above = 0, pets_below = 0;
        for (auto& p : pets) {
            if (p.r < r) pets_above++;
            else if (p.r > r) pets_below++;
            // pets ON the wall row: they'll be displaced/trapped - count against both
        }
        int pets_on = 0;
        for (auto& p : pets) {
            if (p.r == r) pets_on++;
        }

        int area_above = (r - 1) * GRID_SIZE;
        int area_below = (GRID_SIZE - r) * GRID_SIZE;

        double score_above = (double)area_above / 900.0 * std::pow(2.0, -(double)(pets_above + pets_on));
        double score_below = (double)area_below / 900.0 * std::pow(2.0, -(double)(pets_below + pets_on));

        // Penalize wall rows that are far from all humans (takes too long)
        double min_human_dist_to_row = 1e9;
        double avg_human_dist = 0;
        for (int i = 0; i < M; i++) {
            int d = std::abs(humans[i].r - r);
            avg_human_dist += d;
            if (d < min_human_dist_to_row) min_human_dist_to_row = d;
        }
        avg_human_dist /= M;

        // More aggressive penalty for human distance - each turn of travel is a turn not building
        double dist_penalty = 1.0 / (1.0 + avg_human_dist * 0.05);

        bool top = (score_above >= score_below);
        double score = (top ? score_above : score_below) * dist_penalty;

        if (score > best_score) {
            best_score = score;
            best_row = r;
            best_top = top;
        }
    }

    wall_row = best_row;
    go_top = best_top;
}

enum Phase { PHASE_BUILD, PHASE_MOVE_SAFE };
Phase human_phase[10];

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;
    pets.resize(N);
    pet_types.resize(N);
    for (int i = 0; i < N; i++) {
        std::cin >> pets[i].r >> pets[i].c >> pet_types[i];
    }

