        // Assign columns to humans to avoid conflicts
        bool col_claimed[GRID_SIZE + 2];
        memset(col_claimed, false, sizeof(col_claimed));

        // Sort humans by how close they are to any unbuilt wall cell (closest first)
        std::vector<int> order(M);
        for (int i = 0; i < M; i++) order[i] = i;

        std::sort(order.begin(), order.end(), [&](int a, int b) {
            if (human_phase[a] != human_phase[b]) {
                return human_phase[a] < human_phase[b]; // builders first
            }
            int min_a = INF, min_b = INF;
            for (int c = 1; c <= GRID_SIZE; c++) {
                if (!grid[wall_row][c]) {
                    int da = std::abs(humans[a].r - wall_row) + std::abs(humans[a].c - c);
                    int db = std::abs(humans[b].r - wall_row) + std::abs(humans[b].c - c);
                    min_a = std::min(min_a, da);
                    min_b = std::min(min_b, db);
                }
            }
            return min_a < min_b;
        });

        std::vector<Point> walls_being_built;

        for (int idx = 0; idx < M; idx++) {
            int i = order[idx];

            if (human_phase[i] == PHASE_BUILD) {
                // Find nearest unbuilt, unclaimed column
                int target_col = -1;
                int min_dist = INF;

                for (int c = 1; c <= GRID_SIZE; c++) {
                    if (grid[wall_row][c] || col_claimed[c]) continue;
                    int dist = std::abs(humans[i].r - wall_row) + std::abs(humans[i].c - c);
                    // Prefer edge columns (seal from outside in)
                    int edge_bonus = std::min(c - 1, GRID_SIZE - c);
                    int eff_dist = dist + edge_bonus / 2;
                    if (eff_dist < min_dist) {
                        min_dist = eff_dist;
                        target_col = c;
                    }
                }

                if (target_col == -1) {
                    human_phase[i] = PHASE_MOVE_SAFE;
                } else {
                    col_claimed[target_col] = true;

                    // Stand on the safe side of the wall
                    int stand_r = go_top ? wall_row - 1 : wall_row + 1;
                    Point stand_pos = {stand_r, target_col};

                    if (!valid(stand_r, target_col) || !passable(stand_r, target_col)) {
