                int safe_r;
                if (go_top) {
                    safe_r = std::max(1, wall_row / 2);
                } else {
                    safe_r = std::min(GRID_SIZE, wall_row + (GRID_SIZE - wall_row) / 2);
                }
                int safe_c = GRID_SIZE / 2;
                Point target = {safe_r, safe_c};

                // Make sure target is passable
                if (!passable(target.r, target.c)) {
                    bool found = false;
                    int search_start = go_top ? 1 : wall_row + 1;
                    int search_end = go_top ? wall_row - 1 : GRID_SIZE;
                    for (int r = search_start; r <= search_end && !found; r++) {
                        for (int c = 1; c <= GRID_SIZE && !found; c++) {
                            if (passable(r, c)) {
                                target = {r, c};
                                found = true;
                            }
                        }
                    }
                }

                if (humans[i] == target) {
                    actions[i] = '.';
                } else {
                    actions[i] = move_toward(humans[i], target);
                }
            }
        }

        // Validation: check moves don't conflict with walls being built
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (!passable(nr, nc)) {
                            actions[i] = '.';
                            break;
                        }
                        for (auto& w : walls_being_built) {
                            if (w.r == nr && w.c == nc) {
                                actions[i] = '.';
                                break;
                            }
                        }
                        break;
                    }
                }
            }
        }

        std::cout << actions << std::endl;

        // Apply actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (valid(nr, nc)) grid[nr][nc] = true;
                        break;
                    }
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (passable(nr, nc)) humans[i] = {nr, nc};
                        break;
                    }
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N; i++) {
            std::string pet_move;
            std::cin >> pet_move;
            if (pet_move == ".") continue;
            for (char ch : pet_move) {
                for (int d = 0; d < 4; d++) {
                    if (ch == MOVE_CH[d]) {
                        pets[i].r += DR[d];
                        pets[i].c += DC[d];
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
