                    }
                }
            }
        }

        std::cout << actions << std::endl;

        // Apply actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (valid(nr, nc)) grid[nr][nc] = true;
                        break;
                    }
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (passable(nr, nc)) humans[i] = {nr, nc};
