        std::cout << actions << std::endl;

        // Apply actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
