                        }
                    } else {
                        my_claimed[target_col] = true;

                        // Stand on safe side
                        int stand_r;
                        if (human_phase[i] == PHASE_BUILD) {
                            stand_r = (human_wall_assignment[i] == 0) ? wr - 1 : wr + 1;
                        } else {
                            // Helping other wall - stand on same safe side as original assignment
                            stand_r = (human_wall_assignment[i] == 0) ? wr + 1 : wr - 1;
                        }

                        Point stand_pos = {stand_r, target_col};

                        if (!valid(stand_r, target_col) || !passable(stand_r, target_col)) {
                            int alts[4][2] = {
                                {wr - 1, target_col},
                                {wr + 1, target_col},
                                {wr, target_col - 1},
                                {wr, target_col + 1}
                            };
                            bool found = false;
                            for (auto& a : alts) {
                                if (passable(a[0], a[1])) {
                                    stand_pos = {a[0], a[1]};
                                    found = true;
                                    break;
                                }
                            }
                            if (!found) { actions[i] = '.'; continue; }
                        }

                        if (humans[i] == stand_pos) {
                            if (can_build_wall(wr, target_col)) {
                                for (int d = 0; d < 4; d++) {
                                    if (humans[i].r + DR[d] == wr &&
                                        humans[i].c + DC[d] == target_col) {
                                        actions[i] = BUILD_CH[d];
                                        walls_being_built.push_back({wr, target_col});
                                        break;
                                    }
                                }
                            } else {
                                // Pet blocking, try adjacent buildable column
                                my_claimed[target_col] = false;
                                int alt_col = -1;
                                for (int c = 1; c <= GRID_SIZE; c++) {
                                    if (c == target_col) continue;
                                    if (grid[wr][c] || my_claimed[c]) continue;
                                    if (!can_build_wall(wr, c)) continue;
                                    bool adjacent = false;
                                    for (int d = 0; d < 4; d++) {
                                        if (humans[i].r + DR[d] == wr &&
                                            humans[i].c + DC[d] == c) {
                                            adjacent = true;
                                            break;
                                        }
                                    }
                                    if (adjacent) { alt_col = c; break; }
                                }
                                if (alt_col != -1) {
                                    for (int d = 0; d < 4; d++) {
                                        if (humans[i].r + DR[d] == wr &&
                                            humans[i].c + DC[d] == alt_col) {
                                            actions[i] = BUILD_CH[d];
                                            walls_being_built.push_back({wr, alt_col});
                                            my_claimed[alt_col] = true;
                                            break;
                                        }
                                    }
                                } else {
                                    // Move sideways along the wall to find next buildable
                                    int next_c = -1;
                                    int next_dist = INF;
                                    for (int c = 1; c <= GRID_SIZE; c++) {
                                        if (grid[wr][c] || my_claimed[c]) continue;
                                        int d = std::abs(humans[i].c - c);
                                        if (d > 0 && d < next_dist) {
                                            next_dist = d;
                                            next_c = c;
                                        }
                                    }
                                    if (next_c != -1) {
                                        Point next_stand = {stand_pos.r, next_c};
                                        if (passable(next_stand.r, next_stand.c)) {
                                            actions[i] = move_toward(humans[i], next_stand);
                                        }
                                    } else {
                                        actions[i] = '.';
                                    }
                                }
                            }
                        } else {
                            actions[i] = move_toward(humans[i], stand_pos);
                        }
                    }
                }
            }

            do_safe_move:
            if (human_phase[i] == PHASE_MOVE_SAFE) {
                int safe_r;
                if (human_wall_assignment[i] == 0) {
                    int wr = (top_wall_row > 0) ? top_wall_row : bot_wall_row;
                    safe_r = std::max(1, wr / 2);
                } else {
                    int wr = (bot_wall_row > 0) ? bot_wall_row : top_wall_row;
                    safe_r = std::min(GRID_SIZE, wr + (GRID_SIZE - wr) / 2);
                }
                int safe_c = GRID_SIZE / 2;
                Point target = {safe_r, safe_c};

                if (!passable(target.r, target.c)) {
                    int search_start, search_end;
                    if (human_wall_assignment[i] == 0) {
                        search_start = 1;
                        search_end = (top_wall_row > 0) ? top_wall_row - 1 : GRID_SIZE;
                    } else {
                        search_start = (bot_wall_row > 0) ? bot_wall_row + 1 : 1;
                        search_end = GRID_SIZE;
                    }
                    bool found = false;
                    for (int r = search_start; r <= search_end && !found; r++) {
                        for (int c = 1; c <= GRID_SIZE && !found; c++) {
                            if (passable(r, c)) {
                                target = {r, c};
                                found = true;
                            }
                        }
                    }
                }

                if (humans[i] == target) {
                    actions[i] = '.';
                } else {
                    actions[i] = move_toward(humans[i], target);
                }
            }
        }

        // Validate moves
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (!passable(nr, nc)) { actions[i] = '.'; break; }
                        for (auto& w : walls_being_built) {
                            if (w.r == nr && w.c == nc) { actions[i] = '.'; break; }
                        }
                        break;
                    }
                }
            }
        }

        std::cout << actions << std::endl;

        // Apply actions
        for (int i = 0; i < M; i++) {
            char a = actions[i];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == BUILD_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (valid(nr, nc)) grid[nr][nc] = true;
                        break;
                    }
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == MOVE_CH[d]) {
                        int nr = humans[i].r + DR[d], nc = humans[i].c + DC[d];
                        if (passable(nr, nc)) humans[i] = {nr, nc};
                        break;
                    }
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N; i++) {
            std::string pet_move;
            std::cin >> pet_move;
            if (pet_move == ".") continue;
            for (char ch : pet_move) {
                for (int d = 0; d < 4; d++) {
                    if (ch == MOVE_CH[d]) {
                        pets[i].r += DR[d];
                        pets[i].c += DC[d];
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
