void choose_wall_rows() {
    double best_score = -1;
    int best_top = 8, best_bot = 23;

    // Try all pairs of wall rows with enough separation
    for (int tr = 3; tr <= 15; tr++) {
        for (int br = tr + 4; br <= 28; br++) {
            int pets_above = 0, pets_between = 0, pets_below = 0;
            for (auto& p : pets) {
                if (p.r < tr) pets_above++;
                else if (p.r > br) pets_below++;
                else pets_between++; // includes pets ON the wall rows
            }

            int area_above = (tr - 1) * GRID_SIZE;
            int area_below = (GRID_SIZE - br) * GRID_SIZE;

            // Humans in each zone: roughly M/2 each
            int humans_top = M / 2;
            int humans_bot = M - humans_top;

            double score_above = (double)area_above / 900.0 * std::pow(2.0, -(double)pets_above);
            double score_below = (double)area_below / 900.0 * std::pow(2.0, -(double)pets_below);

            // Average satisfaction
