                            adjacent = true;
                            break;
                        }
                    }
                    if (adjacent) { alt_col = c; break; }
                }
                if (alt_col != -1) {
                    for (int d = 0; d < 4; d++) {
                        if (humans[i].r + DR[d] == my_wall_row &&
