if (human_phase[i] == PHASE_BUILD) {
    // Find nearest unbuilt, unclaimed column
    int target_col = -1;
    int min_dist = INF;

    for (int c = 1; c <= GRID_SIZE; c++) {
        if (grid[my_wall_row][c] || my_claimed[c]) continue;
        int dist = std::abs(humans[i].r - my_wall_row) + std::abs(humans[i].c - c);
        if (dist < min_dist) {
            min_dist = dist;
            target_col = c;
        }
    }

    if (target_col == -1) {
        human_phase[i] = PHASE_MOVE_SAFE;
    } else {
        my_claimed[target_col] = true;

        // Stand on the safe side
        int stand_r;
        if (human_wall_assignment[i] == 0) {
            stand_r = my_wall_row - 1; // above top wall
        } else {
            stand_r = my_wall_row + 1; // below bot wall
        }

        Point stand_pos = {stand_r, target_col};

        if (!valid(stand_r, target_col) || !passable(stand_r, target_col)) {
            int alts[4][2] = {
                {my_wall_row - 1, target_col},
                {my_wall_row + 1, target_col},
                {my_wall_row, target_col - 1},
                {my_wall_row, target_col + 1}
            };
            bool found = false;
            for (auto& a : alts) {
                if (passable(a[0], a[1])) {
                    stand_pos = {a[0], a[1]};
                    found = true;
                    break;
                }
            }
            if (!found) { actions[i] = '.'; continue; }
        }

        if (humans[i] == stand_pos) {
